code = """import json

# Get the funding data
funding_data = locals()['var_functions.query_db:62']

# Get civic document text
civic_data = locals().get('var_functions.query_db:51', [])
civic_text = civic_data[0].get('text', '') if civic_data else ''

# Determine project status based on civic documents
def get_project_status(text, project_name):
    if not text:
        return "not available"
    
    base_name = project_name.split('(')[0].strip().lower()
    text_lower = text.lower()
    
    if base_name not in text_lower:
        return "not available"
    
    # Extract context
    lines = text_lower.split('\n')
    context = ""
    for i, line in enumerate(lines):
        if base_name in line:
            context = " ".join(lines[max(0,i-5):min(len(lines),i+10)])
            break
    
    # Check for status indicators
    if any(word in context for word in ['completed', 'notice of completion']):
        return 'completed'
    elif any(word in context for word in ['design', 'planning', 'finalize', 'consultant']):
        return 'design'
    elif any(word in context for word in ['construction', 'under construction']):
        return 'construction'
    elif any(word in context for word in ['pending', 'waiting for', 'application submitted']):
        return 'not started'
    else:
        return 'in progress'

# Process results
results = []
for project in funding_data:
    project_name = project['Project_Name']
    status = get_project_status(civic_text, project_name)
    amount = int(project['Amount'])
    
    results.append({
        'Project_Name': project_name,
        'Funding_Source': project['Funding_Source'],
        'Amount': amount,
        'Status': status
    })

# Create output
output = []
output.append("PROJECTS RELATED TO 'EMERGENCY' OR 'FEMA'")
output.append("=" * 70)

for r in results:
    output.append("Project: " + str(r['Project_Name']))
    output.append("  Funding Source: " + str(r['Funding_Source']))
    output.append("  Amount: $" + "{:,}".format(r['Amount']))
    output.append("  Status: " + str(r['Status']))
    output.append("")

print('__RESULT__:')
print(json.dumps('\n'.join(output)))"""

